insert into public.courses (title, description, image_url, price, is_published, category, instructor_id) values
  ('Introduction to React Native', 'Learn the fundamentals of building mobile apps with React Native. Covers components, styling, navigation, and platform-specific APIs.', 'https://picsum.photos/seed/react-native/800/400', 4999, true, 'Mobile Development', 'seed-instructor-1'),
  ('Advanced TypeScript Patterns', 'Deep dive into TypeScript generics, conditional types, mapped types, and real-world patterns for large-scale applications.', 'https://picsum.photos/seed/typescript/800/400', 7999, true, 'Programming', 'seed-instructor-1'),
  ('Supabase & PostgreSQL Masterclass', 'Build full-stack apps with Supabase. Covers database design, Row Level Security, Edge Functions, and real-time subscriptions.', 'https://picsum.photos/seed/supabase/800/400', 5999, true, 'Backend', 'seed-instructor-2'),
  ('UI/UX Design for Developers', 'Practical design principles every developer should know. Typography, color theory, layout, and building consistent design systems.', 'https://picsum.photos/seed/design/800/400', 3999, true, 'Design', 'seed-instructor-2'),
  ('Expo from Zero to App Store', 'Ship a production app to both app stores. Covers EAS Build, OTA updates, push notifications, and App Store review guidelines.', 'https://picsum.photos/seed/expo/800/400', 8999, true, 'Mobile Development', 'seed-instructor-1'),
  ('Data Structures & Algorithms', 'Master the CS fundamentals that power technical interviews. Arrays, trees, graphs, dynamic programming, and complexity analysis.', 'https://picsum.photos/seed/algorithms/800/400', 0, true, 'Computer Science', 'seed-instructor-3'),
  ('Building REST APIs with Node.js', 'Design and build production-ready REST APIs. Authentication, validation, error handling, testing, and deployment.', 'https://picsum.photos/seed/nodejs/800/400', 4999, false, 'Backend', 'seed-instructor-3');
